queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:benefit_id ?cg . ?child a :Benefits ; p:id ?cg . ?l p:employer_id ?pg . ?parent a :Employers ; p:id ?pg . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Employers } }
  FILTER(?nf = ?total)
}

